import{_ as d,b as o,o as r,i as a,j as n,g as i,aB as l}from"./chunks/framework._ZAOES46.js";const _=JSON.parse('{"title":"FaSparkline 迷你图","description":"","frontmatter":{},"headers":[],"relativePath":"components/pro/FaSparkline.md","filePath":"components/pro/FaSparkline.md"}'),c={name:"components/pro/FaSparkline.md"};function s(p,t,h,m,g,b){const e=o("Badge");return r(),a("div",null,[t[0]||(t[0]=n("div",{style:{display:"none"},hidden:"true","aria-hidden":"true","data-nosnippet":""},"Are you an LLM? You can read better optimized documentation at /components/pro/FaSparkline.md for this page in Markdown format",-1)),i(e,{type:"pro",text:"专业版"}),t[1]||(t[1]=l('<h1 id="fasparkline-迷你图" tabindex="-1">FaSparkline 迷你图 <a class="header-anchor" href="#fasparkline-迷你图" aria-label="Permalink to “FaSparkline 迷你图”">​</a></h1><p>简洁的折线迷你图组件，用于展示数据趋势。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>数据看板趋势展示</li><li>表格中的趋势列</li><li>股票/基金走势</li><li>访问量/销量趋势</li><li>温度/湿度变化</li><li>性能指标监控</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>value</code></td><td><code>number[] | Array&lt;{ value: number, tooltip?: string }&gt;</code></td><td><strong>必需</strong></td><td>数据值</td></tr><tr><td><code>width</code></td><td><code>number</code></td><td><code>100</code></td><td>图表宽度（px）</td></tr><tr><td><code>height</code></td><td><code>number</code></td><td><code>30</code></td><td>图表高度（px）</td></tr><tr><td><code>strokeWidth</code></td><td><code>number</code></td><td><code>2</code></td><td>线条宽度</td></tr><tr><td><code>strokeColor</code></td><td><code>string</code></td><td><code>&#39;oklch(var(--primary))&#39;</code></td><td>线条颜色，同时决定下方渐变填充和端点颜色</td></tr><tr><td><code>cursorColor</code></td><td><code>string</code></td><td><code>跟随 strokeColor</code></td><td>光标颜色</td></tr><tr><td><code>smooth</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否开启圆润曲线过渡</td></tr><tr><td><code>tooltip</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否显示提示</td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><strong>数据格式</strong>：支持简单数字数组或带 tooltip 的对象数组</li><li><strong>自动渐变</strong>：填充区域会基于 <code>strokeColor</code> 自动生成从上到下透明的渐变</li><li><strong>圆润曲线</strong>：开启 <code>smooth</code> 后，折角会过渡成平滑曲线</li><li><strong>响应式重绘</strong>：数据和尺寸变化后会自动重新绘制，并带平滑过渡动画</li><li><strong>无坐标轴</strong>：仅显示趋势线，无坐标轴和标签</li><li><strong>SVG 渲染</strong>：使用 SVG 绘制，清晰度高</li></ol>',8))])}const u=d(c,[["render",s]]);export{_ as __pageData,u as default};
